import numpy as np

class DNAStrand:
    def __init__(self, sequence):
        self.sequence = sequence  # e.g., 'ATCGAT'
        self.complement = self._generate_complement()

    def _generate_complement(self):
        complement_map = {'A': 'T', 'T': 'A', 'C': 'G', 'G': 'C'}
        return ''.join([complement_map[base] for base in self.sequence])

    def hybridize(self, other_strand):
        # Simple hybridization check (Watson-Crick base pairing)
        if self.complement == other_strand.sequence:
            return True
        return False

# Example usage
strand1 = DNAStrand('ATCG')
strand2 = DNAStrand('CGAT')
print(f"Strands hybridize: {strand1.hybridize(strand2)}")

This code models basic DNA strand hybridization, a foundational concept in Yan's work on self-assembling molecular systems.
